package com.hospital.management.util;import com.hospital.management.model.BillItem;import java.math.*;import java.util.*;/** Authoritative decimal billing calculations. */public class BillingCalculator{private static final int SCALE=2;private BigDecimal money(BigDecimal v){if(v==null)return BigDecimal.ZERO.setScale(SCALE);if(v.signum()<0)throw new IllegalArgumentException("Negative amount");return v.setScale(SCALE,RoundingMode.HALF_UP);}public BigDecimal calculateLineTotal(BigDecimal q,BigDecimal p){if(q==null||q.signum()<=0)throw new IllegalArgumentException("Quantity must be positive");return money(q.multiply(money(p)));}public BigDecimal calculateSubtotal(List<BillItem>x){BigDecimal s=BigDecimal.ZERO;for(BillItem i:x==null?List.<BillItem>of():x)s=s.add(money(i.getLineTotal()));return money(s);}public BigDecimal calculateTotal(BigDecimal s,BigDecimal t,BigDecimal d){BigDecimal v=money(s).add(money(t)).subtract(money(d));if(v.signum()<0)throw new IllegalArgumentException("Discount exceeds charges");return money(v);}public BigDecimal calculateBalance(BigDecimal t,BigDecimal p){BigDecimal v=money(t).subtract(money(p));if(v.signum()<0)throw new IllegalArgumentException("Payment exceeds total");return money(v);}public String deriveBillStatus(BigDecimal t,BigDecimal p,String current){if("CANCELLED".equals(current)||"REFUNDED".equals(current))return current;BigDecimal total=money(t),paid=money(p);if(paid.signum()==0)return"UNPAID";if(paid.compareTo(total)>=0)return"PAID";return"PARTIALLY_PAID";}}
